export default function NotebookEdgeSwap(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><div aria-label="Note state" className="grid grid-cols-2 gap-2">{pages.map((page,i)=><button key={page[0]} type="button" aria-pressed={active===i} onClick={()=>setActive(i)} className="min-h-11 rounded-xl border border-[#ececee] bg-white text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{page[0]}</button>)}</div><div className="relative mt-4 overflow-hidden rounded-2xl bg-[#f4f5f6] p-5"><motion.i aria-hidden className="absolute inset-y-0 w-2 bg-[#d8f34e]" animate={{left:active?"calc(100% - 8px)":0}} transition={reduced?{duration:0}:{type:"spring",stiffness:295,damping:27}}/><motion.div key={active} initial={{opacity:0,x:active?12:-12}} animate={{opacity:1,x:0}} transition={reduced?{duration:.12}:{type:"spring",stiffness:295,damping:27}}><h3 className="font-black text-[#111]">{pages[active][0]} note</h3><p className="mt-2 text-sm text-[#4a4a4f]">{pages[active][1]}</p></motion.div></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{pages[active][0]} note selected.</p></section>}
